let selectedNode  = null;
// Function to recursively create HTML element trees
function createElementTree(element) {
  const div = document.createElement('div');
  div.classList.add('element-node');

  // Create the opening tag with styled attributes
  const openingTag = document.createElement('span');
  openingTag.classList.add('opening-tag');

  const attributes = Array.from(element.attributes || []).map(attr => {
    return `<span class="attribute-name">${attr.name}</span>=<span class="attribute-value">"${attr.value}"</span>`;
  }).join(' ');

  openingTag.innerHTML = `&lt;${element.nodeName.toLowerCase()}${attributes ? ` ${attributes}` : ''}&gt;`;

  // Create the toggle button
  const toggleButton = document.createElement('button');
  toggleButton.classList.add('toggle-button');
  toggleButton.appendChild(openingTag);
  div.appendChild(toggleButton);
  toggleButton.classList.add('openable');

  // Container for child nodes
  const childrenContainer = document.createElement('div');
  childrenContainer.style.display = 'none';
  div.appendChild(childrenContainer);

  // Add click functionality to toggle children visibility
  if (element.hasChildNodes()) {
    toggleButton.addEventListener('click', () => {
      if (toggleButton.classList.contains('openable')) {
      const isHidden = childrenContainer.style.display === 'none';
      childrenContainer.style.display = isHidden ? 'block' : 'none';
     toggleButton.classList.toggle('opened')
      }
    });

    // Recursively add children
    Array.from(element.childNodes).forEach(child => {
      if (child.nodeType === Node.ELEMENT_NODE) {
        childrenContainer.appendChild(createElementTree(child));
      } else if (child.nodeType === Node.TEXT_NODE && child.textContent.trim()) {
        // Add text nodes
        const textNode = document.createElement('span');
        textNode.classList.add('text-node');
        textNode.innerHTML = child.textContent.trim().replaceAll('\n','<br>');
        childrenContainer.appendChild(textNode);
     
        if (textNode.innerHTML.split('').length <= 30) {

      childrenContainer.style.display =  'inline'
      textNode.style.marginLeft = '0px'
      toggleButton.classList.remove('openable')
        }
      }
    });

  
  } else {
    childrenContainer.style.display =  'inline'
   
      toggleButton.classList.remove('openable')
  }

  // Add closing tag
  const closingTag = document.createElement('span');
  closingTag.classList.add('closing-tag');
  closingTag.textContent = `</${element.nodeName.toLowerCase()}>`;
  childrenContainer.appendChild(closingTag);

  return div;
}



let clickedConsoleButton = false;
setTimeout(() => {
document.querySelector('.console-toggle').onclick = ()=>{
  return
  if (clickedConsoleButton) return
  clickedConsoleButton = true
// Store the toggle state of nodes
let toggleStates = new Map();

// Function to save toggle states
function saveToggleStates() {
  toggleStates.clear();
  const openButtons = elementsContent.querySelectorAll('.toggle-button.opened');
  const allButtons = elementsContent.querySelectorAll('.toggle-button')
  openButtons.forEach((button,i) => {
    toggleStates.set(`${button.textContent} ${Array.from(allButtons).indexOf(button)}`, true);
  });
}

// Function to restore toggle states
function restoreToggleStates() {
  const allButtons = elementsContent.querySelectorAll('.toggle-button');
  allButtons.forEach((button,i) => {
    if (toggleStates.has(`${button.textContent} ${i}`)) {
      const childrenContainer = button.nextElementSibling;
      childrenContainer.style.display = 'block';
      button.classList.add('opened');
    }
  });
}

// Update elementsContent when the DOM changes
function updateElementTree() {
  saveToggleStates(); // Save current states
  elementsContent.innerHTML = ''; // Clear existing content
  Array.from(document.children).forEach(child => {
    elementsContent.appendChild(createElementTree(child));
  });
  restoreToggleStates(); // Reapply saved states
}

let observerCooldown = 0
// Observe the DOM for changes
const observer = new MutationObserver(mutations => {
  if (observerCooldown <= 0) {
  observer.disconnect()

  updateElementTree();

  observer.observe(document, { childList: true, subtree: true });

  observerCooldown = 20; // Reset cooldown after 100ms to avoid excessive re-renders during rapid DOM changes
  }
});
setInterval(() => observerCooldown--,1)
observer.observe(document, { childList: true, subtree: true });

// Initial render
updateElementTree()
}
},10)
