let lastMessage = { content: null, type: null, element: null, count: 1 };
function appendConsoleMessage(content, type = "log") {

  /* Formatting functions*/
  function formatValue(value) {
    if (typeof value === "string") {
      return `<span class="obj-string">"${value}"</span>`;
    } else if (typeof value === "number") {
      return `<span class="obj-number">${value}</span>`;
    } else if (typeof value === "boolean") {
      return `<span class="obj-boolean">${value}</span>`;
    } else if (value === null) {
      return `<span class="obj-null">null</span>`;
    } else if (value === undefined) {
      return `<span class="obj-undefined">undefined</span>`;
    } else if (typeof value === "function") {
      return `<span class="obj-function">ƒ ${value.name || "(anonymous)"}</span>`;
    } else if (Array.isArray(value)) {
      return formatArray(value);
    } else if (typeof value === "object") {
      return formatObject(value);
    }
    return value.toString();
  }

  function formatArray(arr) {
    const items = arr
      .map((item) => formatValue(item))
      .join('<span class="obj-comma">,</span>');
    return `<span class="obj-brace">[</span>${items}<span class="obj-brace">]</span>`;
  }

  function formatObject(obj) {
    if (obj === null) return '<span class="obj-null">null</span>';
    const pairs = Object.entries(obj)
      .map(([key, value]) => {
        return `<span class="obj-key">${key}</span><span class="obj-colon">:</span>${formatValue(value)}`;
      })
      .join('<span class="obj-comma">,</span>');
    return `<span class="obj-brace">{</span>${pairs}<span class="obj-brace">}</span>`;
  }

  const contentString = typeof content === 'object' && !(content instanceof Error) ? JSON.stringify(content) : String(content);
  

  if (lastMessage.content === contentString && lastMessage.content == contentString &&  lastMessage.type === type && lastMessage.element ){ 
    lastMessage.count++;
    let counter = lastMessage.element.querySelector('.console-counter');
    if (!counter) {
      counter = document.createElement('span');
      counter.className = 'console-counter';
      lastMessage.element.appendChild(counter);
    }
    counter.textContent = `${lastMessage.count}x`;
    return;
  }

  const line = document.createElement("div");
  line.className = `console-line ${type}`;
  
  const icon = document.createElement("span");
  icon.className = "console-icon";
  
  const textSpan = document.createElement("span");
  textSpan.className = "console-text";

  if (content instanceof Error) {
    textSpan.textContent = content.message;
    if (content.stack) {
      const stackSpan = document.createElement("div");
      stackSpan.className = "error-stack";
      stackSpan.textContent = content.stack;
      textSpan.appendChild(stackSpan);
    }
  } else if (typeof content === "object") {
    textSpan.innerHTML = formatValue(content);
  } else {
    textSpan.textContent = String(content);
  }

  line.appendChild(icon);
  line.appendChild(textSpan);
  consoleContent.appendChild(line);
  consoleContent.scrollTop = consoleContent.scrollHeight;

  lastMessage = {
    content: contentString,
    type: type,
    element: line,
    count: 1,
    string: content
  };

  inputField.style.bottom = `calc(225px - ${consoleContent.scrollHeight}px)`;
}

// Performance monitoring (kept the same)
let lastTime = performance.now();
let frames = 0;
const fpsHistory = new Array(60).fill(0);
let historyIndex = 0;

// Create initial FPS bars
const fpsChart = document.getElementById("fps-chart");
fpsHistory.forEach(() => {
  const bar = document.createElement("div");
  bar.classList.add("chart-bar");
  fpsChart.appendChild(bar);
});

function updatePerformance() {
  const now = performance.now();
  frames++;

  // Update FPS every second
  if (now - lastTime >= 500) {
    const fps = Math.round(frames * 1000 / (now - lastTime));
    document.getElementById("fps-value").textContent = fps;

    // Update FPS history
  

    if (historyIndex >= fpsHistory.length-1) {
  
    
      fpsHistory.splice(0,1)
      historyIndex = fpsHistory.length;
      fpsHistory[historyIndex] = fps;

      
     
    } else {
      fpsHistory[historyIndex] = fps;
      historyIndex = (historyIndex + 1);
    }

    // Update chart
    const bars = fpsChart.getElementsByClassName("chart-bar");
    const maxFps = Math.max(...fpsHistory, 60);
    fpsHistory.forEach((fps, i) => {
      const barIndex = (historyIndex + i) % fpsHistory.length;
      const height = (fps / maxFps) * 100;
      bars[barIndex].style.height = `${height}%`;
      bars[barIndex].style.left = `${(i / fpsHistory.length) * 100}%`;
      bars[barIndex].style.backgroundColor = `rgb(0, 255, ${0 })`
    });

    // Update memory usage if available
    if (window.performance && performance.memory) {
      const memoryUsage = Math.round(performance.memory.usedJSHeapSize / (1024 * 1024));
      document.getElementById("memory-value").textContent = `${memoryUsage} MB`;
    }

    frames = 0;
    lastTime = now;
  }

  requestAnimationFrame(updatePerformance);
}

// Start performance monitoring
requestAnimationFrame(updatePerformance);

// Console functionality (kept the same)
const originalConsole = { ...console };
console.log = function (message) {
  originalConsole.log(message);
  appendConsoleMessage(message);
};
console.warn = function (message) {
  originalConsole.warn(message);
  appendConsoleMessage(message, "warning");
};
console.error = function (message) {
  originalConsole.error(message);
  appendConsoleMessage(message, "error");
};

